import { useRef, useState, useEffect } from "react";
import { View, StyleSheet, BackHandler, StatusBar } from "react-native";
import { WebView } from "react-native-webview";

const HTML_B64 = "";

function decodeBase64(str) {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";
  let out = "", i = 0;
  str = str.replace(/[^A-Za-z0-9+/=]/g, "");
  while (i < str.length) {
    const enc1 = chars.indexOf(str[i++]);
    const enc2 = chars.indexOf(str[i++]);
    const enc3 = chars.indexOf(str[i++]);
    const enc4 = chars.indexOf(str[i++]);
    const c1 = (enc1 << 2) | (enc2 >> 4);
    const c2 = ((enc2 & 15) << 4) | (enc3 >> 2);
    const c3 = ((enc3 & 3) << 6) | enc4;
    out += String.fromCharCode(c1);
    if (enc3 !== 64) out += String.fromCharCode(c2);
    if (enc4 !== 64) out += String.fromCharCode(c3);
  }
  try { return decodeURIComponent(escape(out)); } catch(e) { return out; }
}

const HTML = decodeBase64(HTML_B64);

export default function App() {
  const webViewRef = useRef(null);
  const [canGoBack, setCanGoBack] = useState(false);

  useEffect(() => {
    const sub = BackHandler.addEventListener("hardwareBackPress", () => {
      if (canGoBack && webViewRef.current) {
        webViewRef.current.goBack();
        return true;
      }
      return false;
    });
    return () => sub.remove();
  }, [canGoBack]);

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" backgroundColor="#07070F" />
      <WebView
        ref={webViewRef}
        source={{ html: HTML, baseUrl: "about:blank" }}
        style={styles.webview}
        originWhitelist={["*"]}
        javaScriptEnabled={true}
        domStorageEnabled={true}
        mixedContentMode="always"
        onNavigationStateChange={(navState) => setCanGoBack(navState.canGoBack)}
        onError={(e) => console.warn("WebView error:", e.nativeEvent)}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: "#07070F" },
  webview: { flex: 1, backgroundColor: "#07070F" },
});
